tasks.command:
$ErrorActionPreference='Stop'; $app='src/App.tsx'; $css='src/App.css'; $appText=Get-Content -Raw $app; $newBrand=@'
        <div className="hpcan-brand" aria-label="HPCAN branding">
          <span className="hpcan-badge">HPCAN</span>
          <span className="hpcan-name">Hazel Park Community Action Network</span>
        </div>
'@; $appText=[regex]::Replace($appText,'<p className="eyebrow">Hazel Park Library Proposal</p>\s*<div className="hpcan-brand"[\s\S]*?</div>','<p className="eyebrow">Hazel Park Library Proposal</p>' + $newBrand); Set-Content -Path $app -Value $appText; $cssText=Get-Content -Raw $css; $newCss=@'
.hpcan-brand {
  margin-top: 10px;
  display: inline-flex;
  align-items: center;
  gap: 10px;
  padding: 8px 12px;
  border-radius: 999px;
  background: #f6fcf4;
  border: 1px solid rgba(0, 61, 90, 0.25);
  box-shadow: 0 6px 18px rgba(0, 17, 48, 0.18);
}

.hpcan-badge {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  min-width: 58px;
  padding: 4px 10px;
  border-radius: 999px;
  font-size: 0.76rem;
  font-weight: 800;
  letter-spacing: 0.08em;
  color: #fdf5e4;
  background: linear-gradient(135deg, #001130, #003d5a);
}

.hpcan-name {
  font-size: 0.85rem;
  font-weight: 700;
  color: #003d5a;
  letter-spacing: 0.01em;
}
'@; $cssText=[regex]::Replace($cssText,'(?s)\.hpcan-brand \{.*?\}\s*\.hpcan-badge \{.*?\}\s*\.hpcan-name \{.*?\}',''+$newCss.Trim()); Set-Content -Path $css -Value $cssText;

$ErrorActionPreference='Stop'; $css='src/App.css'; $text=Get-Content -Raw $css; if($text -notmatch 'hpcan-name:hover'){ $append=@'
.hpcan-name {
  text-decoration: none;
}

.hpcan-name:hover {
  text-decoration: underline;
  text-underline-offset: 2px;
}
'@; $text = $text + $append; Set-Content -Path $css -Value $text }
